properties.query:
let opValues = dynamic(["Microsoft.SecurityInsights/alertRules/Write", "Microsoft.SecurityInsights/alertRules/Delete"]);
// Azure Sentinel Analytics - Rule Create / Delete
let watchlist_AS_SNTL_041_User = (_GetWatchlist('watchlist_AS_SNTL_041_User')
| project SearchKey);
SentinelAudit
| where OperationName in (opValues)
| sort by TimeGenerated desc
| extend CallerName = tostring(ExtendedProperties.CallerName)
| extend CallerIpAddress = tostring(ExtendedProperties.CallerIpAddress)
| where CallerName !in (watchlist_AS_SNTL_041_User)
| project TimeGenerated, ActorUsername = CallerName, SrcIpAddr = CallerIpAddress, Object = SentinelResourceName, ObjectType = SentinelResourceKind, Operation = OperationName, EventResultDetails = Status
